// Client configurations for lead gen service
// Each client pays $500-2K/mo for leads delivered to their Google Sheet
const clients = [
  {
    id: 'client_001',
    name: 'Example Dental Marketing',
    niche: 'dental practices',
    location: 'Austin TX',
    keywords: ['dentist', 'dental office', 'orthodontist'],
    sheetId: 'CLIENT_SHEET_ID_1',
    leadsPerDay: 10,
    monthlyFee: 500
  },
  {
    id: 'client_002',
    name: 'Example HVAC Leads',
    niche: 'HVAC contractors',
    location: 'Dallas TX',
    keywords: ['HVAC', 'air conditioning', 'heating repair'],
    sheetId: 'CLIENT_SHEET_ID_2',
    leadsPerDay: 15,
    monthlyFee: 1000
  },
  {
    id: 'client_003',
    name: 'Example Legal Leads',
    niche: 'personal injury attorneys',
    location: 'Houston TX',
    keywords: ['personal injury lawyer', 'accident attorney'],
    sheetId: 'CLIENT_SHEET_ID_3',
    leadsPerDay: 8,
    monthlyFee: 2000
  }
];

const today = new Date().toISOString().split('T')[0];
return clients.map(c => ({ json: { ...c, date: today } }));

const clientData = $('Load Client Config').item.json;
const mapsResponse = $input.item.json;

const results = mapsResponse.results || [];
const leads = results.slice(0, clientData.leadsPerDay).map((place, idx) => ({
  leadId: `${clientData.id}_${clientData.date}_${idx + 1}`,
  clientId: clientData.id,
  businessName: place.name || '',
  address: place.formatted_address || '',
  rating: place.rating || 0,
  totalReviews: place.user_ratings_total || 0,
  placeId: place.place_id || '',
  niche: clientData.niche,
  location: clientData.location,
  scrapedAt: new Date().toISOString(),
  status: 'NEW'
}));

return [{ json: { clientId: clientData.id, sheetId: clientData.sheetId, leads, leadCount: leads.length, date: clientData.date } }];

const data = $input.item.json;
const deliveryData = $('Extract and Enrich Leads').item.json;

return [{
  json: {
    clientId: deliveryData.clientId,
    leadsDelivered: deliveryData.leadCount,
    date: deliveryData.date,
    deliveredAt: new Date().toISOString(),
    sheetId: deliveryData.sheetId,
    status: deliveryData.leadCount > 0 ? 'DELIVERED' : 'NO_LEADS'
  }
}];

